SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Cancer type", "Monotherapy/combination", "Number of arms", "Control regimen", "Type of control", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Number of arms" >= 3 AND "Type of control" = 'Chemo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Cancer type", "Monotherapy/combination", "Number of arms", "Control regimen", "Type of control", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Number of arms" >= 3 AND "Type of control" = 'Chemo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Total sample size", "Year", "Cancer type", "Treatment regimen", "Name of ICI", "Class of ICI", "Monotherapy/combination", "Type of combination", "Control regimen", "Type of control", "Lines of treatment", "Clincal setting in relation to surgery", "Primary endpoint", "Priamry Multiple, composite, or co-primary endpoints?", "Secondary endpoint" 
FROM clinical_trials 
WHERE "Cancer type" = 'Small cell lung cancer';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Total sample size", "Follow-up duration for primary endpoint(s) in months | Overall", "Follow-up duration for primary endpoint(s) in months | Rx", "Follow-up duration for primary endpoint(s) in months | Control", "Trial name"
FROM clinical_trials
WHERE "Treatment regimen" = 'Atezolizumab' AND "Cancer type" = 'Multiple Myeloma' AND "Follow-up duration for primary endpoint(s) in months | Overall" > '21';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Total sample size", "Number of arms", "Monotherapy/combination", "Type of control", "Control regimen", "Cancer type", "Treatment regimen", "Name of ICI", "Class of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Number of arms" >= 4 AND "Type of control" = 'Chemo' AND "Control regimen" ILIKE '%anti-VEGF%';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Total sample size", "Monotherapy/combination", "Number of arms", "Control regimen", "Type of control", "Cancer type", "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Number of arms" >= 4 AND "Type of control" = 'Chemo';

SELECT "Author", "Year", "Originial publication or Follow-up", "Included in MA", "Class of ICI", "Cancer type", "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Renal cell' AND ("Class of ICI" = 'PD1' OR "Class of ICI" = 'PD-L1, CTLA-4' OR "Class of ICI" = 'PD1, CTLA-4') AND "Included in MA" = 'Yes';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Total sample size", "Treatment regimen", "Name of ICI", "Class of ICI", "Monotherapy/combination", "Type of control", "Control regimen", "Clinical setting", "Cancer type"
FROM clinical_trials
WHERE "Cancer type" = 'Gastric' AND "Name of ICI" = 'Avelumab' AND "Control regimen" = 'Best supportive care' AND "Type of control" = 'Placebo' OR "Type of control" = 'Best supportive care';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Cancer type", "Treatment regimen", "Name of ICI", "Monotherapy/combination", "Follow-up duration for primary endpoint(s) in months | Overall", "Follow-up duration for primary endpoint(s) in months | Rx", "Follow-up duration for primary endpoint(s) in months | Control"
FROM clinical_trials
WHERE ("Cancer type" = 'Esophageal' OR "Cancer type" = 'Gastroesophageal junction') AND "Follow-up duration for primary endpoint(s) in months | Overall" IS NOT NULL AND "Follow-up duration for primary endpoint(s) in months | Rx" IS NOT NULL AND "Follow-up duration for primary endpoint(s) in months | Control" IS NOT NULL;

SELECT "Author", "Year", "Originial publication or Follow-up", "Type of combination", "Cancer type", "Treatment regimen", "Primary endpoint"
FROM clinical_trials
WHERE "Cancer type" = 'Non-small cell lung cancer' AND "Monotherapy/combination" = 'Combination';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Year", "Primary endpoint", "Priamry Multiple, composite, or co-primary endpoints?", "Secondary endpoint", "Name of ICI", "Treatment regimen", "Type of combination", "Cancer type", "Monotherapy/combination", "Type of combination", "Control regimen", "Type of control", "Clincal setting in relation to surgery", "Follow-up duration for primary endpoint(s) in months | Overall", "Follow-up duration for primary endpoint(s) in months | Rx", "Follow-up duration for primary endpoint(s) in months | Control"
FROM clinical_trials
WHERE "Cancer type" = 'NSCLC' AND "Type of combination" = 'ICI+Vaccine' AND "Monotherapy/combination" = 'Combination';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Cancer type", "Treatment regimen", "Name of ICI", "Monotherapy/combination", "Primary endpoint", "Priamry Multiple, composite, or co-primary endpoints?", "Secondary endpoint", "Type of follow-up given", "Follow-up duration for primary endpoint(s) in months | Overall", "Follow-up duration for primary endpoint(s) in months | Rx", "Follow-up duration for primary endpoint(s) in months | Control"
FROM clinical_trials
WHERE "Cancer type" = 'Non-small cell lung cancer' AND "Follow-up duration for primary endpoint(s) in months | Overall" IS NOT NULL;

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Follow-up duration for primary endpoint(s) in months | Overall", "Follow-up duration for primary endpoint(s) in months | Rx", "Follow-up duration for primary endpoint(s) in months | Control"
FROM clinical_trials
WHERE "Cancer type" = 'Melanoma' AND "Type of follow-up given" = 'Minimum';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Total sample size", "Treatment regimen", "Name of ICI", "Class of ICI", "Monotherapy/combination", "Type of combination", "Control regimen", "Type of control", "Clincal setting in relation to surgery", "Primary endpoint", "Priamry Multiple, composite, or co-primary endpoints?", "Secondary endpoint", "Is PD-L1 positivity inclusion criteria", "Is any other biomarker used for inclusion", "Type of follow-up given", "Follow-up duration for primary endpoint(s) in months | Overall", "Follow-up duration for primary endpoint(s) in months | Rx", "Follow-up duration for primary endpoint(s) in months | Control", "Type of therapy", "Control arm", "Clinical setting", "Included in MA"
FROM clinical_trials
WHERE "Cancer type" = 'Urothelial' AND "Name of ICI" = 'Tremelimumab' AND ("Monotherapy/combination" = 'Combination' OR "Type of combination" IS NOT NULL);

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "PubMed ID", "Cancer type", "Treatment regimen", "Name of ICI", "Class of ICI", "Monotherapy/combination", "Type of combination", "Control regimen", "Type of control", "Clinical setting", "Trial phase", "Total sample size"
FROM clinical_trials
WHERE ("Cancer type" = 'Gastric' OR "Cancer type" = 'Gastric/GEJ' OR "Cancer type" = 'Gastroesophageal junction') AND "Year" >= 2018;

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Bladder' AND "Class of ICI" = 'PD-L1';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Class of ICI"
FROM clinical_trials
WHERE "Cancer type" = 'Bladder' AND "Class of ICI" IS NOT NULL AND "Name of ICI" IS NOT NULL;

SELECT "Treatment regimen", "Monotherapy/combination", "Name of ICI", "Class of ICI", "Type of combination", "Control regimen", "Type of control", "Cancer type", "Trial phase"
FROM clinical_trials
WHERE "Cancer type" = 'Renal cell' AND "Trial phase" = 'Phase 3' AND ("Class of ICI" LIKE '%PD1%' OR "Name of ICI" LIKE '%PD-1%' OR "Name of ICI" LIKE '%PD1%') AND "Monotherapy/combination" = 'Combination';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Monotherapy/combination", "Type of therapy", "Clincal setting in relation to surgery", "Priamry Multiple, composite, or co-primary endpoints?", "Cancer type"
FROM clinical_trials
WHERE "Cancer type" = 'Multiple Myeloma' AND "Clincal setting in relation to surgery" LIKE '%Neoadjuvant%' AND "Name of ICI" IS NOT NULL;

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Cancer type", "Control regimen", "Type of control", "Monotherapy/combination", "Number of arms", "Treatment regimen"
FROM clinical_trials
WHERE "Cancer type" = 'Non-Small Cell Lung' AND "Number of arms" >= 4 AND "Type of control" = 'Chemo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Treatment regimen", "Name of ICI", "Class of ICI", "Monotherapy/combination", "Type of combination", "Control regimen", "Type of control", "Trial phase", "Total sample size", "Originial publication or Follow-up", "Cancer type"
FROM clinical_trials
WHERE "Cancer type" = 'Mesothelioma' AND "Trial phase" = 'Phase 3' AND ("Treatment regimen" LIKE '%immunotherapy%' OR "Name of ICI" IS NOT NULL) AND "Type of control" = 'Chemo';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Trial name", "Total sample size", "Cancer type", "Treatment regimen", "Name of ICI", "Class of ICI", "Monotherapy/combination", "Type of combination", "Control regimen", "Type of control", "Clincal setting in relation to surgery", "Primary endpoint", "Priamry Multiple, composite, or co-primary endpoints?" 
FROM clinical_trials 
WHERE "Cancer type" = 'Mesothelioma' AND "Trial phase" = 'Phase 3' AND "Monotherapy/combination" = 'Monotherapy' OR "Monotherapy/combination" = 'Combination' 
AND ("Name of ICI" IS NOT NULL OR "Class of ICI" IS NOT NULL) 
AND EXISTS (
  SELECT 1 FROM (
    SELECT "NCT" 
  ) AS t
);
